import { useState, useMemo, useRef, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const DELIVERY_STATUSES = ["Diproses", "Barang Diambil", "Dalam Perjalanan", "Tiba di Tujuan"];
const MOCK_ORDERS = [
  { id: "LGA-29402", customer: "PT. Samudera Raya", date: "12 Okt 2023, 14:20", deliveryStatus: "Dalam Perjalanan", initials: "PT", avatarBg: "#F59E0B", avatarText: "#fff" },
  { id: "LGA-29405", customer: "Andi Maulana",       date: "12 Okt 2023, 15:45", deliveryStatus: "Dalam Perjalanan", initials: "AM", avatarBg: "#9CA3AF", avatarText: "#fff" },
  { id: "LGA-29408", customer: "Global Food Corp",   date: "12 Okt 2023, 19:10", deliveryStatus: "Dalam Perjalanan", initials: "GF", avatarBg: "#6EE7B7", avatarText: "#065F46" },
  { id: "LGA-29412", customer: "Eka Lestari",        date: "13 Okt 2023, 08:30", deliveryStatus: "Dalam Perjalanan", initials: "EL", avatarBg: "#FDE68A", avatarText: "#92400E" },
  { id: "LGA-29415", customer: "Budi Santoso",       date: "13 Okt 2023, 10:00", deliveryStatus: "Diproses",         initials: "BS", avatarBg: "#BFDBFE", avatarText: "#1E40AF" },
  { id: "LGA-29418", customer: "Sari Indah",         date: "13 Okt 2023, 11:30", deliveryStatus: "Barang Diambil",  initials: "SI", avatarBg: "#F9A8D4", avatarText: "#9D174D" },
];

const PAGE_SIZE = 4;

function StatusDropdown({ value, onChange }) {
  const [open, setOpen] = useState(false);
  const [rect, setRect] = useState(null);
  const btnRef = useRef(null);
  const dropdownRef = useRef(null); // ← tambah ref untuk dropdown

  useEffect(() => {
    const handler = (e) => {
      // ← cek apakah klik di luar KEDUA elemen
      if (
        btnRef.current && !btnRef.current.contains(e.target) &&
        dropdownRef.current && !dropdownRef.current.contains(e.target)
      ) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleOpen = () => {
    if (btnRef.current) setRect(btnRef.current.getBoundingClientRect());
    setOpen((v) => !v);
  };

  return (
    <div style={{ position: "relative" }}>
      <button ref={btnRef} onClick={handleOpen} /* ... styling tetap sama */ >
        {value}
        {/* ... svg arrow tetap sama */}
      </button>

      {open && rect && createPortal(
        <div
          ref={dropdownRef} // ← pasang ref di sini
          style={{ position: "fixed", top: rect.bottom + 4, left: rect.left, /* ... styling tetap sama */ }}
        >
          {DELIVERY_STATUSES.map((s) => (
            <button key={s} onClick={() => { onChange(s); setOpen(false); }}
              /* ... styling tetap sama */
            >
              {s}
            </button>
          ))}
        </div>,
        document.body
      )}
    </div>
  );
}

function SuccessModal({ open, onClose }) {
  if (!open) return null;
  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.4)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 9999,
    }}>
      <div style={{
        background: "#fff", borderRadius: 16, padding: "48px 40px",
        textAlign: "center", minWidth: 340, boxShadow: "0 20px 60px rgba(0,0,0,0.15)",
      }}>
        <svg width="52" height="52" viewBox="0 0 52 52" fill="none" style={{ margin: "0 auto 20px" }}>
          <circle cx="26" cy="26" r="26" fill="#D1FAE5"/>
          <path d="M15 26L22 33L37 18" stroke="#10B981" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
        <div style={{ fontSize: 17, fontWeight: 800, color: "#111827", letterSpacing: 1, marginBottom: 24 }}>
          PERUBAHAN BERHASIL
        </div>
        <button
          onClick={onClose}
          style={{
            background: "#F59E0B", color: "#fff", border: "none",
            borderRadius: 8, padding: "10px 32px", fontSize: 14,
            fontWeight: 700, cursor: "pointer",
          }}
        >
          Tutup
        </button>
      </div>
    </div>
  );
}

export default function StatusPengiriman() {
  const navigate = useNavigate();
  const [orders, setOrders] = useState(MOCK_ORDERS);
  const [page, setPage] = useState(1);
  const [showSuccess, setShowSuccess] = useState(false);

  const totalPages = Math.max(1, Math.ceil(orders.length / PAGE_SIZE));

  const items = useMemo(() => {
    const start = (page - 1) * PAGE_SIZE;
    return orders.slice(start, start + PAGE_SIZE);
  }, [orders, page]);

  const startIndex = (page - 1) * PAGE_SIZE;

  const handleStatusChange = (id, status) => {
    setOrders((prev) => prev.map((o) => o.id === id ? { ...o, deliveryStatus: status } : o));
  };

  const handleSave = () => setShowSuccess(true);

  return (
    <>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap');`}</style>

      <div style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", background: "#F8F9FB", minHeight: "100vh" }}>
        <main style={{ padding: "40px 40px" }}>
          <h1 style={{ fontSize: 28, fontWeight: 800, color: "#111827", margin: 0 }}>
            Status Pengiriman
          </h1>
          <p style={{ fontSize: 13, color: "#9CA3AF", marginTop: 4, marginBottom: 28 }}>
            Perbaharui Status Pengiriman
          </p>

          <div style={{
            background: "#fff", borderRadius: 14,
            border: "1px solid #F0F0F0",
            boxShadow: "0 1px 6px rgba(0,0,0,0.04)",
            overflow: "hidden",
          }}>
            <div style={{
              display: "grid",
              gridTemplateColumns: "1fr 1.4fr 1fr 1.8fr",
              gap: 16, padding: "14px 28px",
              background: "#FAFAFA", borderBottom: "1px solid #F0F0F0",
            }}>
              {["ID PESANAN", "NAMA PELANGGAN", "TANGGAL", "STATUS"].map((h) => (
                <div key={h} style={{ fontSize: 11, fontWeight: 700, color: "#9CA3AF", letterSpacing: 0.8, textAlign: "center" }}>{h}</div>
              ))}
            </div>

            <div>
              {items.map((o, i) => (
                <div key={o.id} style={{
                  display: "grid",
                  gridTemplateColumns: "1fr 1.4fr 1fr 1.8fr",
                  gap: 16, padding: "18px 28px",
                  alignItems: "center",
                  borderBottom: i < items.length - 1 ? "1px solid #F9FAFB" : "none",
                }}>
                  <div style={{ fontSize: 13, fontWeight: 800, color: "#111827", textAlign: "center" }}>#{o.id}</div>

                  <div style={{ display: "flex", alignItems: "center", justifyContent: "flex-start", gap: 16 }}>
                    <div style={{
                      width: 34, height: 34, borderRadius: 8,
                      background: o.avatarBg, color: o.avatarText,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      fontSize: 11, fontWeight: 800, flexShrink: 0,
                    }}>{o.initials}</div>
                    <span style={{ fontSize: 13, color: "#111827", fontWeight: 500 }}>{o.customer}</span>
                  </div>

                  <div style={{ fontSize: 13, color: "#6B7280", textAlign: "center" }}>{o.date}</div>

                  <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
                    <button
                      onClick={() => navigate(`/invoice/${o.id}`)}
                      style={{
                        background: "#F59E0B", color: "#fff", border: "none",
                        borderRadius: 6, padding: "0 12px", height: 32,
                        fontSize: 11, fontWeight: 700, cursor: "pointer",
                        whiteSpace: "nowrap",
                      }}>
                      Upload Invoice
                    </button>

                    <StatusDropdown
                      value={o.deliveryStatus}
                      onChange={(s) => handleStatusChange(o.id, s)}
                    />
                  </div>
                </div>
              ))}
            </div>

            <div style={{
              display: "flex", alignItems: "center", justifyContent: "space-between",
              padding: "12px 28px", background: "#FAFAFA", borderTop: "1px solid #F0F0F0",
            }}>
              <div style={{ fontSize: 11, color: "#9CA3AF" }}>
                MENAMPILKAN {startIndex + 1}-{Math.min(startIndex + PAGE_SIZE, orders.length)} DARI {orders.length} TRANSAKSI
              </div>
              <div style={{ display: "flex", gap: 6 }}>
                {[
                  { label: "<", action: () => setPage((p) => Math.max(1, p - 1)), disabled: page === 1 },
                  { label: ">", action: () => setPage((p) => Math.min(totalPages, p + 1)), disabled: page === totalPages },
                ].map((btn) => (
                  <button key={btn.label} onClick={btn.action} disabled={btn.disabled} style={{
                    width: 30, height: 30, border: "1px solid #E5E7EB", borderRadius: 6,
                    background: "#fff", fontSize: 13, color: "#374151",
                    cursor: btn.disabled ? "not-allowed" : "pointer",
                    opacity: btn.disabled ? 0.4 : 1, fontFamily: "inherit",
                  }}>{btn.label}</button>
                ))}
              </div>
            </div>
          </div>

          <button
            onClick={handleSave}
            style={{
              marginTop: 24, background: "#F59E0B", color: "#fff", border: "none",
              borderRadius: 8, padding: "12px 28px", fontSize: 14, fontWeight: 700,
              cursor: "pointer",
            }}
          >
            Simpan Perubahan
          </button>
        </main>
      </div>

      <SuccessModal open={showSuccess} onClose={() => setShowSuccess(false)} />
    </>
  );
}
